parameters.jsCode:
const body = $input.first().json.body || {};
const branding = body.branding || {};
const copy = body.copy || {};
const strategy = body.strategy || {};
const images = branding.images || {};
const colors = Array.isArray(branding.colors) ? branding.colors : Object.values(branding.colors || {});
const fontsList = Array.isArray(branding.fonts) ? branding.fonts.map((f) => typeof f === "string" ? f : f.family).filter(Boolean) : [];
const palette = colors.slice(0, 6).join(", ") || "brand colors";
const fonts = fontsList.slice(0, 3).join(", ") || "";
const brandName = copy.brand_name || branding.title || "the brand";
const tone = (copy.tone || []).join(", ") || (strategy.mood_keywords || []).slice(0,3).join(", ") || "modern, confident";
const headline = copy.hero_headline || copy.tagline || "";
const cta = copy.primary_cta || "";
const archetype = strategy.brand_archetype || "";
const designMd = String(body.design_md || "").slice(0, 2400);
const hasHttpLogo = new RegExp("^https?://").test(images.logo || "");
const hasScreenshot = new RegExp("^data:image/(png|jpe?g|webp);base64,").test(body.screenshot || "");
const imageUrls = [
  hasHttpLogo ? images.logo : null,
  hasScreenshot ? body.screenshot : null,
  images.ogImage,
].filter(Boolean);

const referenceRules = [
  "Reference priority is strict: 1) the logo/brand mark, 2) the homepage screenshot, 3) the OG image only as secondary inspiration.",
  "The generated asset must visibly belong to the same brand system as the logo: match the mark geometry, color relationships, contrast, spacing, and level of polish.",
  "Do not invent a different logo, mascot, app icon, or unrelated symbol. If a mark appears, it should be derived from the provided logo reference.",
  "Use the homepage screenshot for layout density, surface treatment, typography feel, and real product context.",
  "Use the OG image only for broad mood if it conflicts with the logo or homepage screenshot."
].join(" ");

const baseStyle = referenceRules + " Brand: " + brandName + ". Tone: " + tone + ". " + (archetype ? "Archetype: " + archetype + ". " : "") + "Palette: " + palette + ". " + (fonts ? "Typography: " + fonts + ". " : "") + "Headline: " + headline + ". CTA: " + cta + ". Crisp readable text is allowed only when it improves the asset. Design system context: " + designMd;

if (body.asset_prompt) {
  return [{ json: {
    type: body.asset_type || "custom",
    image_size: body.image_size || "landscape_16_9",
    image_urls: imageUrls,
    prompt: body.asset_prompt + "

Brand context:
" + baseStyle,
  }}];
}

return [
  { json: { type: "hero", image_size: "landscape_16_9", image_urls: imageUrls, prompt: "Hero marketing image for " + brandName + ". " + baseStyle + " Concept: " + (headline || "the brand promise") + ". High-end website hero visual." } },
  { json: { type: "ig_post", image_size: "square_hd", image_urls: imageUrls, prompt: "Instagram post for " + brandName + ". " + baseStyle + " Square composition with one strong subject and short readable text treatment: "" + brandName + "". Premium." } },
  { json: { type: "og_card", image_size: "landscape_16_9", image_urls: imageUrls, prompt: "Open Graph social card for " + brandName + ". " + baseStyle + " Wide branded card with readable title text: "" + (headline || brandName) + """ + (cta ? " and small CTA text "" + cta + """ : "") + "." } },
  { json: { type: "ig_story", image_size: "portrait_16_9", image_urls: imageUrls, prompt: "Instagram story for " + brandName + ". " + baseStyle + " Tall vertical branded composition with crisp readable text and safe space near top and bottom." } }
];
